sql:
SELECT date_time, pm2_5_ug_m3
FROM air_quality_readings
WHERE pm2_5_ug_m3 > 30;

SELECT pm2_5_ug_m3, temperature_deg_c
FROM air_quality_readings
WHERE reading_id = 0;

SELECT username, email
FROM users
WHERE user_id IN (
    SELECT DISTINCT user_id
    FROM data_quality
);

external_knowledge:
- 'Up-to-date' maintenance status refers to a station with a next scheduled maintenance date in the future; 
- 'Overdue' maintenance status refers to a station with a next scheduled maintenance date in the past;
- PM10 and PM2.5 levels are measured in micrograms per cubic meter; 
- Quality score is a measure of the reliability of the air quality reading;
- Alert type and severity are used to categorize the level of air quality, with possible values including 'PM10 high', 'PM2.5 high', 'low', 'medium', and 'high'.

sql:
SELECT station_id, COUNT(*) AS reading_count
FROM air_quality_readings
GROUP BY station_id;

SELECT pm2_5_ug_m3
FROM air_quality_readings
WHERE station_id = (SELECT station_id FROM monitoring_stations WHERE site_name = 'Central Park');
